 1	import * as React from 'react';
 2	import { render, screen } from '@testing-library/react';
 3	import { userEvent } from '@testing-library/user-event';
 4	import { GettingStartedExpandableGrid } from './GettingStartedExpandableGrid';
 5	
 6	const children = 'Testing children prop';
 7	const title = 'Getting started test';
 8	const setIsOpen = jest.fn(() => null);
 9	
10	describe('Test getting started expandable card/grid (GettingStartedExpandableGrid)', () => {
11	  afterEach(() => jest.clearAllMocks());
12	
13	  it('Renders card/grid with expandable open', async () => {
14	    const user = userEvent.setup();
15	    const { container } = render(
16	      <GettingStartedExpandableGrid
17	        isOpen={true}
18	        setIsOpen={setIsOpen}
19	        title={title}
20	      >
21	        {children}
22	      </GettingStartedExpandableGrid>
23	    );
24	
25	    expect(screen.getByText(title)).toBeInTheDocument();
26	    expect(screen.getByText(children)).toBeInTheDocument();
27	    expect(screen.getByText(children)).toBeVisible();
28	
29	    const expandable = container.querySelector(
30	      '[data-test="getting-started-expandable"]'
31	    ) as HTMLElement;
32	    expect(expandable).toBeInTheDocument();
33	
34	    const toggleButton = screen.getByRole('button', { name: title });
35	    expect(toggleButton).toBeInTheDocument();
36	    await user.click(toggleButton);
37	    expect(setIsOpen).toHaveBeenCalledTimes(1);
38	  });
39	
40	  it('Renders card/grid with expandable collapsed', async () => {
41	    const user = userEvent.setup();
42	    const { container } = render(
43	      <GettingStartedExpandableGrid
44	        isOpen={false}
45	        setIsOpen={setIsOpen}
46	        title={title}
47	      >
48	        {children}
49	      </GettingStartedExpandableGrid>
50	    );
51	
52	    expect(screen.getByText(title)).toBeInTheDocument();
53	    expect(screen.getByText(children)).toBeInTheDocument();
54	    expect(screen.getByText(children)).not.toBeVisible();
55	
56	    const expandable = container.querySelector(
57	      '[data-test="getting-started-expandable"]'
58	    ) as HTMLElement;
59	    expect(expandable).toBeInTheDocument();
60	
61	    const toggleButton = screen.getByRole('button', { name: title });
62	    expect(toggleButton).toBeInTheDocument();
63	    await user.click(toggleButton);
64	    expect(setIsOpen).toHaveBeenCalledTimes(1);
65	  });
66	
67	  it('Renders card/grid without expandable', async () => {
68	    const { container } = render(
69	      <GettingStartedExpandableGrid
70	        isOpen={true}
71	        setIsOpen={setIsOpen}
72	        title={title}
73	        hideExpandable={true}
74	      >
75	        {children}
76	      </GettingStartedExpandableGrid>
77	    );
78	
79	    expect(screen.getByText(title)).toBeInTheDocument();
80	    expect(screen.getByText(children)).toBeInTheDocument();
81	    expect(screen.getByText(children)).toBeVisible();
82	
83	    expect(
84	      container.querySelector('[data-test="getting-started-expandable"]')
85	    ).not.toBeInTheDocument();
86	
87	    let error;
88	    try {
89	      expect(screen.getByRole('button', { name: title })).toThrow();
90	    } catch (e) {
91	      error = e;
92	    }
93	    expect(error).toBeInstanceOf(Error);
94	  });
95	});

